@page "/patients"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success ms-2" @onclick="ShowAddPet" disabled="@(!owners.Any())">+ New Patient</button>
    </div>
    <div class="col-auto">
        <input type="text" class="form-control" placeholder="Search pets..." @bind="searchTerm" @bind:event="oninput" />
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="First Name" @bind="editingOwner.FirstName" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Last Name" @bind="editingOwner.LastName" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Phone" @bind="editingOwner.Phone" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Email" @bind="editingOwner.Email" />
                </div>
            </div>
            <button class="btn btn-primary mt-2" @onclick="SaveOwner">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showOwnerForm = false">Cancel</button>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingPet.Id == 0 ? "Register New Patient" : "Edit Patient")</h5>
            <div class="row g-2">
                <div class="col-md-2">
                    <input class="form-control" placeholder="Name" @bind="editingPet.Name" />
                </div>
                <div class="col-md-2">
                    <select class="form-select" @bind="editingPet.Species">
                        <option value="">Species</option>
                        <option>Dog</option>
                        <option>Cat</option>
                        <option>Bird</option>
                        <option>Rabbit</option>
                        <option>Reptile</option>
                        <option>Other</option>
                    </select>
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Breed" @bind="editingPet.Breed" />
                </div>
                <div class="col-md-2">
                    <input type="date" class="form-control" @bind="editingPet.DateOfBirth" />
                </div>
                <div class="col-md-1">
                    <select class="form-select" @bind="editingPet.Sex">
                        <option value="">Sex</option>
                        <option>Male</option>
                        <option>Female</option>
                    </select>
                </div>
                <div class="col-md-1">
                    <input type="number" step="0.1" class="form-control" placeholder="Kg" @bind="editingPet.WeightKg" />
                </div>
                <div class="col-md-2">
                    <select class="form-select" @bind="editingPet.OwnerId">
                        <option value="0">Select Owner</option>
                        @foreach (var o in owners)
                        {
                            <option value="@o.Id">@o.FirstName @o.LastName</option>
                        }
                    </select>
                </div>
            </div>
            <button class="btn btn-primary mt-2" @onclick="SavePet">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showPetForm = false">Cancel</button>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var pet in FilteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ViewHistory(pet)">History</button>
                    <button class="btn btn-sm btn-outline-danger" @onclick="() => DeletePet(pet)">Delete</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (showHistory)
{
    <div class="card mt-3">
        <div class="card-header d-flex justify-content-between">
            <span>Medical History - @selectedPet!.Name</span>
            <button class="btn btn-sm btn-success" @onclick="ShowAddTreatment">+ Add Treatment</button>
        </div>
        <div class="card-body">
            @if (showTreatmentForm)
            {
                <div class="row g-2 mb-3">
                    <div class="col-md-3">
                        <input type="date" class="form-control" @bind="editingTreatment.Date" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Description" @bind="editingTreatment.Description" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Veterinarian" @bind="editingTreatment.Veterinarian" />
                    </div>
                    <div class="col-md-3">
                        <button class="btn btn-primary" @onclick="SaveTreatment">Save</button>
                        <button class="btn btn-secondary" @onclick="() => showTreatmentForm = false">Cancel</button>
                    </div>
                    <div class="col-12 mt-1">
                        <textarea class="form-control" rows="2" placeholder="Notes" @bind="editingTreatment.Notes"></textarea>
                    </div>
                </div>
            }
            <table class="table table-sm">
                <thead><tr><th>Date</th><th>Description</th><th>Vet</th><th>Notes</th></tr></thead>
                <tbody>
                    @foreach (var t in treatments)
                    {
                        <tr>
                            <td>@t.Date.ToShortDateString()</td>
                            <td>@t.Description</td>
                            <td>@t.Veterinarian</td>
                            <td>@t.Notes</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

@code {
    private List<Pet> pets = [];
    private List<Owner> owners = [];
    private List<Treatment> treatments = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPetForm, showHistory, showTreatmentForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();
    private Treatment editingTreatment = new();
    private Pet? selectedPet;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowAddOwner() { editingOwner = new(); showOwnerForm = true; }
    private void ShowAddPet() { editingPet = new(); showPetForm = true; }

    private async Task SaveOwner()
    {
        if (string.IsNullOrWhiteSpace(editingOwner.FirstName)) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner.Id == 0) db.Owners.Add(editingOwner);
        else db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (string.IsNullOrWhiteSpace(editingPet.Name) || editingPet.OwnerId == 0) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        if (editingPet.Id == 0) db.Pets.Add(editingPet);
        else db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species, Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth, Sex = pet.Sex, WeightKg = pet.WeightKg, OwnerId = pet.OwnerId
        };
        showPetForm = true;
    }

    private async Task DeletePet(Pet pet)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Pets.FindAsync(pet.Id);
        if (entity != null) { db.Pets.Remove(entity); await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task ViewHistory(Pet pet)
    {
        selectedPet = pet;
        showHistory = true;
        await using var db = await DbFactory.CreateDbContextAsync();
        treatments = await db.Treatments.Where(t => t.PetId == pet.Id).OrderByDescending(t => t.Date).ToListAsync();
    }

    private void ShowAddTreatment()
    {
        editingTreatment = new Treatment { PetId = selectedPet!.Id, Date = DateTime.Now };
        showTreatmentForm = true;
    }

    private async Task SaveTreatment()
    {
        if (string.IsNullOrWhiteSpace(editingTreatment.Description)) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        db.Treatments.Add(editingTreatment);
        await db.SaveChangesAsync();
        showTreatmentForm = false;
        await ViewHistory(selectedPet!);
    }
}

@page "/appointments"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddForm">+ New Appointment</button>
    </div>
    <div class="col-auto">
        <input type="date" class="form-control" @bind="selectedDate" @bind:event="onchange" @bind:after="LoadAppointments" />
    </div>
    <div class="col-auto">
        <select class="form-select" @bind="filterStatus" @bind:after="LoadAppointments">
            <option value="">All Statuses</option>
            <option value="Scheduled">Scheduled</option>
            <option value="Completed">Completed</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editing.Id == 0 ? "New Appointment" : "Edit Appointment")</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <label class="form-label">Patient</label>
                    <select class="form-select" @bind="editing.PetId">
                        <option value="0">Select Patient</option>
                        @foreach (var p in pets)
                        {
                            <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-2">
                    <label class="form-label">Start</label>
                    <input type="datetime-local" class="form-control" @bind="editing.StartTime" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">End</label>
                    <input type="datetime-local" class="form-control" @bind="editing.EndTime" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Veterinarian</label>
                    <input class="form-control" @bind="editing.Veterinarian" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Reason</label>
                    <input class="form-control" @bind="editing.Reason" />
                </div>
                <div class="col-12">
                    <textarea class="form-control mt-1" rows="2" placeholder="Notes" @bind="editing.Notes"></textarea>
                </div>
            </div>
            @if (conflictWarning != null)
            {
                <div class="alert alert-warning mt-2">@conflictWarning</div>
            }
            <button class="btn btn-primary mt-2" @onclick="SaveAppointment">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showForm = false">Cancel</button>
        </div>
    </div>
}

<h4 class="mt-3">Schedule for @selectedDate.ToString("dddd, MMMM d, yyyy")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead>
                <tr><th>Time</th><th>Patient</th><th>Vet</th><th>Reason</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var apt in appointments)
                {
                    <tr class="@GetRowClass(apt)">
                        <td>@apt.StartTime.ToString("HH:mm") - @apt.EndTime.ToString("HH:mm")</td>
                        <td>@apt.Pet.Name</td>
                        <td>@apt.Veterinarian</td>
                        <td>@apt.Reason</td>
                        <td><span class="badge @GetBadgeClass(apt.Status)">@apt.Status</span></td>
                        <td>
                            @if (apt.Status == AppointmentStatus.Scheduled)
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(apt)">Reschedule</button>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                                <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                            }
                        </td>
                    </tr>
                }
                @if (!appointments.Any())
                {
                    <tr><td colspan="6" class="text-center text-muted">No appointments for this date</td></tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Available Slots</div>
            <div class="card-body">
                @foreach (var slot in availableSlots)
                {
                    <span class="badge bg-success me-1 mb-1">@slot</span>
                }
                @if (!availableSlots.Any())
                {
                    <p class="text-muted">No available slots</p>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private List<Appointment> appointments = [];
    private List<Pet> pets = [];
    private List<string> availableSlots = [];
    private DateTime selectedDate = DateTime.Today;
    private string filterStatus = "";
    private bool showForm;
    private Appointment editing = new();
    private string? conflictWarning;

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == selectedDate.Date);

        if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<AppointmentStatus>(filterStatus, out var status))
            query = query.Where(a => a.Status == status);

        appointments = await query.OrderBy(a => a.StartTime).ToListAsync();
        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var scheduled = appointments.Where(a => a.Status == AppointmentStatus.Scheduled).ToList();
        for (int hour = 8; hour < 18; hour++)
        {
            var slotStart = selectedDate.Date.AddHours(hour);
            var slotEnd = slotStart.AddMinutes(30);
            bool taken = scheduled.Any(a => a.StartTime < slotEnd && a.EndTime > slotStart);
            if (!taken) availableSlots.Add($"{hour:D2}:00");

            slotStart = selectedDate.Date.AddHours(hour).AddMinutes(30);
            slotEnd = slotStart.AddMinutes(30);
            taken = scheduled.Any(a => a.StartTime < slotEnd && a.EndTime > slotStart);
            if (!taken) availableSlots.Add($"{hour:D2}:30");
        }
    }

    private void ShowAddForm()
    {
        editing = new Appointment
        {
            StartTime = selectedDate.Date.AddHours(9),
            EndTime = selectedDate.Date.AddHours(9).AddMinutes(30)
        };
        conflictWarning = null;
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        if (editing.PetId == 0 || string.IsNullOrWhiteSpace(editing.Reason)) return;

        await using var db = await DbFactory.CreateDbContextAsync();

        // Check for conflicts
        var conflict = await db.Appointments.AnyAsync(a =>
            a.Id != editing.Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.StartTime < editing.EndTime &&
            a.EndTime > editing.StartTime);

        if (conflict)
        {
            conflictWarning = "This time slot conflicts with an existing appointment!";
            return;
        }

        if (editing.Id == 0)
            db.Appointments.Add(editing);
        else
            db.Appointments.Update(editing);

        await db.SaveChangesAsync();
        showForm = false;
        conflictWarning = null;
        await LoadAppointments();
    }

    private void Reschedule(Appointment apt)
    {
        editing = new Appointment
        {
            Id = apt.Id, PetId = apt.PetId, StartTime = apt.StartTime, EndTime = apt.EndTime,
            Reason = apt.Reason, Veterinarian = apt.Veterinarian, Notes = apt.Notes, Status = apt.Status
        };
        conflictWarning = null;
        showForm = true;
    }

    private async Task Complete(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null) { entity.Status = AppointmentStatus.Completed; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private async Task Cancel(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null) { entity.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private string GetRowClass(Appointment a) => a.Status switch
    {
        AppointmentStatus.Cancelled => "table-secondary",
        AppointmentStatus.Completed => "table-success",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-dark"
    };
}

@page "/billing"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing</PageTitle>

<h1>Billing &amp; Payments</h1>

<div class="row mb-3">
    <div class="col">
        <button class="btn btn-primary" @onclick="ShowAddInvoice">+ New Invoice</button>
    </div>
    <div class="col-auto">
        <select class="form-select" @bind="invoiceFilter" @bind:after="LoadInvoices">
            <option value="all">All Invoices</option>
            <option value="unpaid">Unpaid Only</option>
            <option value="paid">Paid Only</option>
        </select>
    </div>
</div>

@if (showInvoiceForm)
{
