    private List<Treatment> treatments = [];
    private string searchTerm = "";
    private bool showOwnerForm, showPetForm, showHistory, showTreatmentForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();
    private Treatment editingTreatment = new();
    private Pet? selectedPet;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p => p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowAddOwner() { editingOwner = new(); showOwnerForm = true; }
    private void ShowAddPet() { editingPet = new(); showPetForm = true; }

    private async Task SaveOwner()
    {
        if (string.IsNullOrWhiteSpace(editingOwner.FirstName)) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner.Id == 0) db.Owners.Add(editingOwner);
        else db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (string.IsNullOrWhiteSpace(editingPet.Name) || editingPet.OwnerId == 0) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        if (editingPet.Id == 0) db.Pets.Add(editingPet);
        else db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species, Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth, Sex = pet.Sex, WeightKg = pet.WeightKg, OwnerId = pet.OwnerId
        };
        showPetForm = true;
    }

    private async Task DeletePet(Pet pet)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Pets.FindAsync(pet.Id);
        if (entity != null) { db.Pets.Remove(entity); await db.SaveChangesAsync(); }
        await LoadData();
    }

    private async Task ViewHistory(Pet pet)
    {
        selectedPet = pet;
        showHistory = true;
        await using var db = await DbFactory.CreateDbContextAsync();
        treatments = await db.Treatments.Where(t => t.PetId == pet.Id).OrderByDescending(t => t.Date).ToListAsync();
