                    {
                        <tr>
                            <td>@pay.PaidDate.ToShortDateString()</td>
                            <td>$@pay.Amount.ToString("F2")</td>
                            <td>@pay.Method</td>
                            <td>@pay.Reference</td>
                        </tr>
                    }
                    @if (!paymentHistory.Any())
                    {
                        <tr><td colspan="4" class="text-muted text-center">No payments recorded</td></tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

@code {
    private List<Invoice> invoices = [];
    private List<Pet> pets = [];
    private List<Payment> paymentHistory = [];
    private string invoiceFilter = "all";
    private bool showInvoiceForm, showPayForm, showPaymentHistory;
    private Invoice newInvoice = new() { IssuedDate = DateTime.Now };
    private Payment newPayment = new() { PaidDate = DateTime.Now };
    private Invoice? selectedInvoice;
    private decimal paidSoFar;

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner).AsQueryable();
        query = invoiceFilter switch
        {
            "unpaid" => query.Where(i => !i.IsPaid),
            "paid" => query.Where(i => i.IsPaid),
            _ => query
        };
        invoices = await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    private void ShowAddInvoice()
    {
        newInvoice = new Invoice { IssuedDate = DateTime.Now };
        showInvoiceForm = true;
    }

    private async Task SaveInvoice()
    {
        if (newInvoice.PetId == 0 || newInvoice.Amount <= 0) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        db.Invoices.Add(newInvoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private async Task ShowPaymentForm(Invoice inv)
    {
        selectedInvoice = inv;
        await using var db = await DbFactory.CreateDbContextAsync();
        paidSoFar = await db.Payments.Where(p => p.InvoiceId == inv.Id).SumAsync(p => p.Amount);
        newPayment = new Payment { InvoiceId = inv.Id, PaidDate = DateTime.Now, Amount = inv.Amount - paidSoFar };
        showPayForm = true;
        showPaymentHistory = false;
    }

    private async Task ProcessPayment()
    {
        if (newPayment.Amount <= 0) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(newPayment);

        var totalPaid = await db.Payments.Where(p => p.InvoiceId == newPayment.InvoiceId).SumAsync(p => p.Amount) + newPayment.Amount;
        var invoice = await db.Invoices.FindAsync(newPayment.InvoiceId);
        if (invoice != null && totalPaid >= invoice.Amount)
            invoice.IsPaid = true;

        await db.SaveChangesAsync();
        showPayForm = false;
        await LoadInvoices();
    }

    private async Task ViewPayments(Invoice inv)
    {
        selectedInvoice = inv;
        await using var db = await DbFactory.CreateDbContextAsync();
        paymentHistory = await db.Payments.Where(p => p.InvoiceId == inv.Id).OrderByDescending(p => p.PaidDate).ToListAsync();
        showPaymentHistory = true;
        showPayForm = false;
    }
}

