    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == selectedDate.Date);

        if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<AppointmentStatus>(filterStatus, out var status))
            query = query.Where(a => a.Status == status);

        appointments = await query.OrderBy(a => a.StartTime).ToListAsync();
        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var scheduled = appointments.Where(a => a.Status == AppointmentStatus.Scheduled).ToList();
        for (int hour = 8; hour < 18; hour++)
        {
            var slotStart = selectedDate.Date.AddHours(hour);
            var slotEnd = slotStart.AddMinutes(30);
            bool taken = scheduled.Any(a => a.StartTime < slotEnd && a.EndTime > slotStart);
            if (!taken) availableSlots.Add($"{hour:D2}:00");

            slotStart = selectedDate.Date.AddHours(hour).AddMinutes(30);
            slotEnd = slotStart.AddMinutes(30);
            taken = scheduled.Any(a => a.StartTime < slotEnd && a.EndTime > slotStart);
            if (!taken) availableSlots.Add($"{hour:D2}:30");
        }
    }

    private void ShowAddForm()
    {
        editing = new Appointment
        {
            StartTime = selectedDate.Date.AddHours(9),
            EndTime = selectedDate.Date.AddHours(9).AddMinutes(30)
        };
        conflictWarning = null;
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        if (editing.PetId == 0 || string.IsNullOrWhiteSpace(editing.Reason)) return;

        await using var db = await DbFactory.CreateDbContextAsync();

        // Check for conflicts
        var conflict = await db.Appointments.AnyAsync(a =>
            a.Id != editing.Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.StartTime < editing.EndTime &&
            a.EndTime > editing.StartTime);

        if (conflict)
        {
            conflictWarning = "This time slot conflicts with an existing appointment!";
            return;
        }

        if (editing.Id == 0)
            db.Appointments.Add(editing);
        else
            db.Appointments.Update(editing);

        await db.SaveChangesAsync();
        showForm = false;
        conflictWarning = null;
        await LoadAppointments();
    }

    private void Reschedule(Appointment apt)
    {
        editing = new Appointment
        {
            Id = apt.Id, PetId = apt.PetId, StartTime = apt.StartTime, EndTime = apt.EndTime,
            Reason = apt.Reason, Veterinarian = apt.Veterinarian, Notes = apt.Notes, Status = apt.Status
        };
        conflictWarning = null;
        showForm = true;
    }

    private async Task Complete(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null) { entity.Status = AppointmentStatus.Completed; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private async Task Cancel(Appointment apt)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity != null) { entity.Status = AppointmentStatus.Cancelled; await db.SaveChangesAsync(); }
        await LoadAppointments();
    }

    private string GetRowClass(Appointment a) => a.Status switch
    {
        AppointmentStatus.Cancelled => "table-secondary",
        AppointmentStatus.Completed => "table-success",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-dark"
    };
}
