@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</h5>
            <div class="row g-2">
                <div class="col-md-3">
