                </div>
            </div>
            <button class="btn btn-primary mt-2" @onclick="SaveOwner">Save</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showOwnerForm = false">Cancel</button>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingPet.Id == 0 ? "Register New Patient" : "Edit Patient")</h5>
            <div class="row g-2">
                <div class="col-md-2">
                    <input class="form-control" placeholder="Name" @bind="editingPet.Name" />
                </div>
                <div class="col-md-2">
                    <select class="form-select" @bind="editingPet.Species">
                        <option value="">Species</option>
                        <option>Dog</option>
                        <option>Cat</option>
                        <option>Bird</option>
                        <option>Rabbit</option>
                        <option>Reptile</option>
                        <option>Other</option>
                    </select>
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Breed" @bind="editingPet.Breed" />
                </div>
                <div class="col-md-2">
                    <input type="date" class="form-control" @bind="editingPet.DateOfBirth" />
