@page "/billing"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing</PageTitle>

<h1>Billing &amp; Payments</h1>

<div class="row mb-3">
    <div class="col">
        <button class="btn btn-primary" @onclick="ShowAddInvoice">+ New Invoice</button>
    </div>
    <div class="col-auto">
        <select class="form-select" @bind="invoiceFilter" @bind:after="LoadInvoices">
            <option value="all">All Invoices</option>
            <option value="unpaid">Unpaid Only</option>
            <option value="paid">Paid Only</option>
        </select>
    </div>
</div>

@if (showInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>New Invoice</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <label class="form-label">Patient</label>
                    <select class="form-select" @bind="newInvoice.PetId">
                        <option value="0">Select Patient</option>
                        @foreach (var p in pets)
                        {
                            <option value="@p.Id">@p.Name (@p.Owner.LastName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-2">
                    <label class="form-label">Amount ($)</label>
                    <input type="number" step="0.01" class="form-control" @bind="newInvoice.Amount" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Date</label>
                    <input type="date" class="form-control" @bind="newInvoice.IssuedDate" />
                </div>
                <div class="col-md-5">
                    <label class="form-label">Description</label>
                    <input class="form-control" @bind="newInvoice.Description" />
                </div>
            </div>
            <button class="btn btn-primary mt-2" @onclick="SaveInvoice">Create Invoice</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showInvoiceForm = false">Cancel</button>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr><th>#</th><th>Date</th><th>Patient</th><th>Description</th><th>Amount</th><th>Status</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>INV-@inv.Id.ToString("D4")</td>
                <td>@inv.IssuedDate.ToShortDateString()</td>
                <td>@inv.Pet.Name</td>
                <td>@inv.Description</td>
                <td>$@inv.Amount.ToString("F2")</td>
                <td>
                    @if (inv.IsPaid)
                    {
                        <span class="badge bg-success">Paid</span>
                    }
                    else
                    {
                        <span class="badge bg-danger">Unpaid</span>
                    }
                </td>
                <td>
                    @if (!inv.IsPaid)
                    {
                        <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPaymentForm(inv)">Record Payment</button>
                    }
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ViewPayments(inv)">History</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (showPayForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>Record Payment for INV-@selectedInvoice!.Id.ToString("D4")</h5>
            <p>Outstanding: $@((selectedInvoice!.Amount - paidSoFar).ToString("F2"))</p>
            <div class="row g-2">
                <div class="col-md-2">
                    <label class="form-label">Amount ($)</label>
                    <input type="number" step="0.01" class="form-control" @bind="newPayment.Amount" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Date</label>
                    <input type="date" class="form-control" @bind="newPayment.PaidDate" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Method</label>
                    <select class="form-select" @bind="newPayment.Method">
                        @foreach (var m in Enum.GetValues<PaymentMethod>())
                        {
                            <option value="@m">@m</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Reference</label>
                    <input class="form-control" @bind="newPayment.Reference" />
                </div>
            </div>
            <button class="btn btn-success mt-2" @onclick="ProcessPayment">Process</button>
            <button class="btn btn-secondary mt-2" @onclick="() => showPayForm = false">Cancel</button>
        </div>
    </div>
}

@if (showPaymentHistory)
{
    <div class="card mt-3">
        <div class="card-header">Payment History - INV-@selectedInvoice!.Id.ToString("D4")</div>
        <div class="card-body">
            <table class="table table-sm">
                <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                <tbody>
                    @foreach (var pay in paymentHistory)
                    {
                        <tr>
                            <td>@pay.PaidDate.ToShortDateString()</td>
                            <td>$@pay.Amount.ToString("F2")</td>
                            <td>@pay.Method</td>
                            <td>@pay.Reference</td>
                        </tr>
                    }
                    @if (!paymentHistory.Any())
                    {
                        <tr><td colspan="4" class="text-muted text-center">No payments recorded</td></tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
}

@code {
    private List<Invoice> invoices = [];
    private List<Pet> pets = [];
    private List<Payment> paymentHistory = [];
    private string invoiceFilter = "all";
    private bool showInvoiceForm, showPayForm, showPaymentHistory;
    private Invoice newInvoice = new() { IssuedDate = DateTime.Now };
    private Payment newPayment = new() { PaidDate = DateTime.Now };
    private Invoice? selectedInvoice;
    private decimal paidSoFar;

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner).AsQueryable();
        query = invoiceFilter switch
        {
            "unpaid" => query.Where(i => !i.IsPaid),
            "paid" => query.Where(i => i.IsPaid),
            _ => query
        };
        invoices = await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    private void ShowAddInvoice()
    {
        newInvoice = new Invoice { IssuedDate = DateTime.Now };
        showInvoiceForm = true;
    }

    private async Task SaveInvoice()
    {
        if (newInvoice.PetId == 0 || newInvoice.Amount <= 0) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        db.Invoices.Add(newInvoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private async Task ShowPaymentForm(Invoice inv)
    {
        selectedInvoice = inv;
        await using var db = await DbFactory.CreateDbContextAsync();
        paidSoFar = await db.Payments.Where(p => p.InvoiceId == inv.Id).SumAsync(p => p.Amount);
        newPayment = new Payment { InvoiceId = inv.Id, PaidDate = DateTime.Now, Amount = inv.Amount - paidSoFar };
        showPayForm = true;
        showPaymentHistory = false;
    }

    private async Task ProcessPayment()
    {
        if (newPayment.Amount <= 0) return;
        await using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(newPayment);

        var totalPaid = await db.Payments.Where(p => p.InvoiceId == newPayment.InvoiceId).SumAsync(p => p.Amount) + newPayment.Amount;
        var invoice = await db.Invoices.FindAsync(newPayment.InvoiceId);
        if (invoice != null && totalPaid >= invoice.Amount)
            invoice.IsPaid = true;

        await db.SaveChangesAsync();
        showPayForm = false;
        await LoadInvoices();
    }

    private async Task ViewPayments(Invoice inv)
    {
        selectedInvoice = inv;
        await using var db = await DbFactory.CreateDbContextAsync();
        paymentHistory = await db.Payments.Where(p => p.InvoiceId == inv.Id).OrderByDescending(p => p.PaidDate).ToListAsync();
        showPaymentHistory = true;
        showPayForm = false;
    }
}

